mapper.sql:
SELECT ROW_NUMBER() OVER (ORDER BY A.CD_SEQNO ASC, A.CMMN_CD_ID DESC) AS "LINE_NO" /* Row Number */ , A.UP_CD AS "UP_CD" /* 공통코드 분류코드 */ , B.CDNM AS "UP_CDNM" /* 공통코드 분류코드명 */ , A.CD AS "CD" /* 공통코드 */ , A.CDNM AS "CDNM" /* 공통코드명 */ , A.CD_SEQNO AS "CD_SEQNO" /* 코드 순서 */ , A.USEYN AS "USEYN" /* 사용여부 */ , A.CMMN_CD_ID AS "CMMN_CD_ID" /* 공통코드 ID */ FROM TB_LMS_CMMN_CD A JOIN TB_LMS_CMMN_CD B ON A.UP_CD = B.CD AND B.UP_CD = B.CD WHERE A.ORG_ID = #{orgId}
AND A.UP_CD = A.CD AND A.USEYN = 'Y'
AND A.UP_CD != A.CD AND A.UP_CD = #{upCd}
AND A.CDNM LIKE '%' || #{cdnm} || '%'

mapper.update:
	/*
		SQL ID : sysCmmnCdDAO.updateSysCmmnUpCd
		설명 : 시스템 상위 공통코드 수정
 	*/
	UPDATE
		TB_LMS_CMMN_CD
	SET
		UP_CD		=	#{updtUpCd}
		, CD		= 	#{updtUpCd}
		, CDNM		=	#{upCdnm}
		, MDFR_ID	=	#{mdfrId}
		, MOD_DTTM	=	TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	WHERE
		CMMN_CD_ID = #{cmmnCdId}
		AND ORG_ID = #{orgId}
		AND UP_CD = CD

mapper.delete:
	/*
		SQL ID : sysCmmnCdDAO.deleteSysCmmnUpCd
		설명 : 시스템 상위 공통코드 삭제
 	*/
	DELETE FROM
		TB_LMS_CMMN_CD
	WHERE
		UP_CD = #{upCd}
		AND ORG_ID = #{orgId}

