AND A.USEYN = 'Y'
)

mapper.update:
	/*
		SQL ID : sysCmmnCdDAO.updateSysCmmnCd
		설명 : 시스템 공통코드 수정
 	*/
	UPDATE
		TB_LMS_CMMN_CD
	SET




		UP_CD		=	#{updtUpCd}
		, MDFR_ID	=	#{mdfrId}
		, MOD_DTTM	=	TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	WHERE
		UP_CD = #{upCd}
		AND ORG_ID = #{orgId}
		AND UP_CD != CD



		CD			=	#{cd}
		, CDNM		=	#{cdnm}
		, CD_SEQNO	=	#{cdSeqno}
		, USEYN		=	#{useyn}
		, MDFR_ID	=	#{mdfrId}
		, MOD_DTTM	=	TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	WHERE
		CMMN_CD_ID = #{cmmnCdId}

mapper.delete:
	/*
		SQL ID : sysCmmnCdDAO.deleteSysCmmnCd
		설명 : 시스템 공통코드 삭제
 	*/
	DELETE FROM
		TB_LMS_CMMN_CD
	WHERE


		UP_CD = #{upCd}
		AND ORG_ID = #{orgId}


		CMMN_CD_ID = #{cmmnCdId}
		AND ORG_ID = #{orgId}
